/**
 * <dregg-ontology> — the EFFECT CATALOG browser.
 *
 * Teaches the full dregg2 effect ontology: every `FullActionA` variant, its
 * wire mnemonic, typed args, one-line semantics, the authorization facet it
 * needs, and its category. The data is `ontology-catalog.generated.json`,
 * generated by `site/tools/gen-ontology-catalog.js` DIRECTLY from the verified
 * Lean source (TurnExecutorFull.lean + FFI.lean), so this surface cannot drift
 * from the executor it documents.
 *
 * Usage:
 *   <dregg-ontology></dregg-ontology>
 * Attributes:
 *   src   — override the catalog URL (default '/_includes/studio/ontology-catalog.generated.json')
 *   q     — initial search query
 *   cat   — initial category filter
 *
 * No runtime / node needed: this is pure documentation generated from source.
 */

const CATALOG_URL = '/_includes/studio/ontology-catalog.generated.json';

// Per-category accent (uses site palette via color-mix; one stable hue per group).
const CAT_HUE = {
  value:     '#5b8a5a',
  state:     '#c8a050',
  authority: '#c86060',
  lifecycle: '#5080c8',
  escrow:    '#9060c0',
  privacy:   '#a050a0',
  seal:      '#50a0a8',
  bridge:    '#c87830',
  queue:     '#5aa0a0',
  swiss:     '#8a78c0',
  other:     '#8a948f',
};

const FACET_DESC = {
  write:   'mutates a cell record / the ledger',
  grant:   'moves or mints capability (not cell state)',
  control: 'nested exercise — re-enters the privileged path',
};

function esc(s) {
  if (s == null) return '';
  return String(s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function catColor(cat) {
  const hue = CAT_HUE[cat] || CAT_HUE.other;
  return `background:color-mix(in srgb,${hue} 20%,var(--bg-raised));color:${hue}`;
}

class DreggOntology extends HTMLElement {
  static get observedAttributes() { return ['q', 'cat']; }

  connectedCallback() {
    this._q = this.getAttribute('q') || '';
    this._cat = this.getAttribute('cat') || '';
    // dregg://effect/<name> deep link (resolver.js → ?effect=<name>).
    try {
      const want = new URLSearchParams(window.location.search).get('effect');
      if (want && !this._q) this._q = want;
    } catch { /* embedded without URL context */ }
    this._loadAndRender();
  }

  async _loadAndRender() {
    if (!this._catalog) {
      const url = this.getAttribute('src') || CATALOG_URL;
      this.innerHTML = `<div class="dregg-onto__loading">Loading effect catalog…</div>`;
      try {
        const res = await fetch(url, { headers: { Accept: 'application/json' } });
        if (!res.ok) throw new Error(`status ${res.status}`);
        this._catalog = await res.json();
      } catch (err) {
        this.innerHTML =
          `<div class="dregg-inspector dregg-inspector--err">` +
          `Could not load ontology catalog (${esc(err && err.message || err)}). ` +
          `Run <code>node site/tools/gen-ontology-catalog.js</code> and rebuild the site.</div>`;
        return;
      }
    }
    this._render();
  }

  _render() {
    const cat = this._catalog;
    const effects = cat.effects || [];
    const q = (this._q || '').trim().toLowerCase();
    const catFilter = this._cat || '';

    const filtered = effects.filter((e) => {
      if (catFilter && e.category !== catFilter) return false;
      if (!q) return true;
      const hay = [
        e.ctor, e.wire, e.category, e.facet, e.semantics,
        ...(e.args || []).map((a) => `${a.name} ${a.type}`),
      ].join(' ').toLowerCase();
      return hay.includes(q);
    });

    const cov = cat.coverage || {};
    const categories = cat.categories || [];

    // --- chrome: header + coverage banner + search + category chips --------
    const header =
      `<div class="dregg-onto__head">` +
        `<div class="dregg-onto__title">Effect ontology` +
          `<span class="dregg-onto__count">${cat.effect_count} variants</span>` +
        `</div>` +
        `<div class="dregg-onto__prov">` +
          `Generated from the verified Lean source ` +
          `(<code>FullActionA</code> + <code>requiredFacetA</code> + the <code>encodeActionW</code> wire codec). ` +
          `Coverage: facet ${cov.effects_with_facet}/${cat.effect_count}, ` +
          `wire ${cov.effects_with_wire}/${cat.effect_count}.` +
        `</div>` +
      `</div>`;

    const search =
      `<div class="dregg-onto__controls">` +
        `<input class="dregg-onto__search" type="search" placeholder="search effects, args, semantics…" ` +
          `value="${esc(this._q)}" aria-label="search effects">` +
        `<div class="dregg-onto__cats">` +
          `<button class="dregg-onto__cat${catFilter === '' ? ' is-on' : ''}" data-cat="">all</button>` +
          categories.map((c) => {
            const n = effects.filter((e) => e.category === c).length;
            if (!n) return '';
            return `<button class="dregg-onto__cat${catFilter === c ? ' is-on' : ''}" ` +
              `data-cat="${esc(c)}" style="${catColor(c)}">${esc(c)} ${n}</button>`;
          }).join('') +
        `</div>` +
      `</div>`;

    // --- effect list -------------------------------------------------------
    const list = filtered.length
      ? filtered.map((e) => this._effectCard(e)).join('')
      : `<div class="dregg-inspector--empty">no effects match “${esc(q)}”` +
        (catFilter ? ` in category ${esc(catFilter)}` : '') + `</div>`;

    this.innerHTML =
      `<div class="dregg-onto">` + header + search +
      `<div class="dregg-onto__results">${list}</div></div>`;

    // wire interactions
    const input = this.querySelector('.dregg-onto__search');
    if (input) {
      input.addEventListener('input', () => {
        this._q = input.value;
        // re-render only the results + chip counts; keep focus
        this._renderResultsOnly();
      });
    }
    this.querySelectorAll('.dregg-onto__cat').forEach((b) => {
      b.addEventListener('click', () => {
        this._cat = b.getAttribute('data-cat') || '';
        this._render();
      });
    });
    this.querySelectorAll('.dregg-onto__card-head').forEach((h) => {
      h.addEventListener('click', () => {
        const card = h.closest('.dregg-onto__card');
        if (card) card.classList.toggle('is-open');
      });
    });
  }

  // Lightweight results-only refresh on keystroke (avoids losing input focus).
  _renderResultsOnly() {
    const cat = this._catalog;
    const effects = cat.effects || [];
    const q = (this._q || '').trim().toLowerCase();
    const catFilter = this._cat || '';
    const filtered = effects.filter((e) => {
      if (catFilter && e.category !== catFilter) return false;
      if (!q) return true;
      const hay = [e.ctor, e.wire, e.category, e.facet, e.semantics,
        ...(e.args || []).map((a) => `${a.name} ${a.type}`)].join(' ').toLowerCase();
      return hay.includes(q);
    });
    const results = this.querySelector('.dregg-onto__results');
    if (!results) return;
    results.innerHTML = filtered.length
      ? filtered.map((e) => this._effectCard(e)).join('')
      : `<div class="dregg-inspector--empty">no effects match “${esc(q)}”` +
        (catFilter ? ` in category ${esc(catFilter)}` : '') + `</div>`;
    results.querySelectorAll('.dregg-onto__card-head').forEach((h) => {
      h.addEventListener('click', () => {
        const card = h.closest('.dregg-onto__card');
        if (card) card.classList.toggle('is-open');
      });
    });
  }

  _effectCard(e) {
    const args = (e.args || []).map((a) =>
      `<span class="dregg-onto__arg"><span class="dregg-onto__arg-name">${esc(a.name)}</span>` +
      `<span class="dregg-onto__arg-type">${esc(a.type)}</span></span>`
    ).join('');
    const facetDesc = FACET_DESC[e.facet] || '';
    return (
      `<div class="dregg-onto__card">` +
        `<div class="dregg-onto__card-head">` +
          `<code class="dregg-onto__ctor">${esc(e.ctor)}</code>` +
          (e.wire ? `<code class="dregg-onto__wire" title="wire mnemonic">${esc(e.wire)}</code>` : '') +
          `<span class="dregg-onto__cat-chip" style="${catColor(e.category)}">${esc(e.category)}</span>` +
          (e.facet ? `<span class="dregg-onto__facet" title="${esc(facetDesc)}">needs&nbsp;${esc(e.facet)}</span>` : '') +
        `</div>` +
        `<div class="dregg-onto__card-body">` +
          `<div class="dregg-onto__sem">${esc(e.semantics)}</div>` +
          (args ? `<div class="dregg-onto__args"><span class="dregg-onto__args-label">args</span>${args}</div>` : '') +
          (e.facet ? `<div class="dregg-onto__facet-line"><span class="dregg-onto__args-label">auth</span>` +
            `<code>Authority.Auth.${esc(e.facet)}</code> — ${esc(facetDesc)}</div>` : '') +
        `</div>` +
      `</div>`
    );
  }
}

if (!customElements.get('dregg-ontology')) {
  customElements.define('dregg-ontology', DreggOntology);
}

// --- styles (site palette only) --------------------------------------------
(function injectStyles() {
  if (document.getElementById('dregg-ontology-styles')) return;
  const s = document.createElement('style');
  s.id = 'dregg-ontology-styles';
  s.textContent = `
.dregg-onto { font-family: var(--font-mono, ui-monospace, monospace); }
.dregg-onto__loading { color: var(--fg-dim); padding: var(--s3, 10px); }
.dregg-onto__head { margin-bottom: var(--s3, 10px); }
.dregg-onto__title { display:flex; align-items:baseline; gap:10px; font-size:1.1rem; color:var(--fg); font-weight:600; }
.dregg-onto__count { font-size:0.8rem; color:var(--fg-dim); font-weight:normal; }
.dregg-onto__prov { font-size:0.78rem; color:var(--fg-dim); margin-top:4px; line-height:1.5; }
.dregg-onto__prov code { color:var(--fg); }
.dregg-onto__controls { position:sticky; top:0; background:var(--bg); padding:var(--s2,6px) 0; z-index:1; border-bottom:1px solid var(--line); margin-bottom:var(--s3,10px); }
.dregg-onto__search { width:100%; box-sizing:border-box; padding:8px 10px; font:inherit; background:var(--bg-raised); color:var(--fg); border:1px solid var(--line); border-radius:6px; }
.dregg-onto__search:focus { outline:none; border-color:var(--accent,#5b8a5a); }
.dregg-onto__cats { display:flex; flex-wrap:wrap; gap:6px; margin-top:8px; }
.dregg-onto__cat { padding:3px 10px; font:inherit; font-size:0.74rem; cursor:pointer; background:var(--bg-raised); color:var(--fg-dim); border:1px solid var(--line); border-radius:12px; }
.dregg-onto__cat:hover { border-color:var(--accent,#5b8a5a); }
.dregg-onto__cat.is-on { outline:2px solid var(--accent,#5b8a5a); color:var(--fg); }
.dregg-onto__results { display:flex; flex-direction:column; gap:6px; }
.dregg-onto__card { border:1px solid var(--line); border-radius:6px; background:var(--bg-raised); overflow:hidden; }
.dregg-onto__card-head { display:flex; align-items:center; flex-wrap:wrap; gap:8px; padding:8px 10px; cursor:pointer; }
.dregg-onto__card-head:hover { background:color-mix(in srgb,var(--accent,#5b8a5a) 8%,var(--bg-raised)); }
.dregg-onto__ctor { font-size:0.9rem; color:var(--fg); font-weight:600; }
.dregg-onto__wire { font-size:0.74rem; color:var(--fg-dim); background:var(--bg); padding:1px 6px; border-radius:3px; border:1px solid var(--line); }
.dregg-onto__cat-chip { font-size:0.7rem; padding:1px 8px; border-radius:3px; font-weight:600; }
.dregg-onto__facet { margin-left:auto; font-size:0.72rem; color:var(--fg-dim); }
.dregg-onto__card-body { padding:0 10px 10px 10px; }
.dregg-onto__card.is-open .dregg-onto__card-body { display:block; }
.dregg-onto__sem { font-size:0.82rem; color:var(--fg); line-height:1.55; margin:4px 0 8px; }
.dregg-onto__args, .dregg-onto__facet-line { display:flex; align-items:baseline; flex-wrap:wrap; gap:6px; font-size:0.78rem; margin-top:4px; }
.dregg-onto__args-label { font-size:0.68rem; text-transform:uppercase; letter-spacing:0.05em; color:var(--fg-dim); min-width:34px; }
.dregg-onto__arg { display:inline-flex; gap:4px; align-items:baseline; padding:1px 7px; background:var(--bg); border:1px solid var(--line); border-radius:3px; }
.dregg-onto__arg-name { color:var(--fg); }
.dregg-onto__arg-type { color:var(--fg-dim); font-size:0.72rem; }
.dregg-onto__facet-line code { color:var(--accent-bright,#7db87b); }
`;
  document.head.appendChild(s);
})();
